def _databricks_volume_to_nested(
    databricks_volume: DatabricksVolume,
) -> DatabricksVolumeNested:
    """Convert flat DatabricksVolume to nested format."""
    attrs = DatabricksVolumeAttributes()
    _populate_databricks_volume_attrs(attrs, databricks_volume)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        databricks_volume,
        _DATABRICKS_VOLUME_REL_FIELDS,
        DatabricksVolumeRelationshipAttributes,
    )
    return DatabricksVolumeNested(
        guid=databricks_volume.guid,
        type_name=databricks_volume.type_name,
        status=databricks_volume.status,
        version=databricks_volume.version,
        create_time=databricks_volume.create_time,
        update_time=databricks_volume.update_time,
        created_by=databricks_volume.created_by,
        updated_by=databricks_volume.updated_by,
        classifications=databricks_volume.classifications,
        classification_names=databricks_volume.classification_names,
        meanings=databricks_volume.meanings,
        labels=databricks_volume.labels,
        business_attributes=databricks_volume.business_attributes,
        custom_attributes=databricks_volume.custom_attributes,
        pending_tasks=databricks_volume.pending_tasks,
        proxy=databricks_volume.proxy,
        is_incomplete=databricks_volume.is_incomplete,
        provenance_type=databricks_volume.provenance_type,
        home_id=databricks_volume.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _databricks_volume_from_nested(nested: DatabricksVolumeNested) -> DatabricksVolume:
    """Convert nested format to flat DatabricksVolume."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DatabricksVolumeAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DATABRICKS_VOLUME_REL_FIELDS,
        DatabricksVolumeRelationshipAttributes,
    )
    return DatabricksVolume(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_databricks_volume_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _databricks_volume_to_nested_bytes(
    databricks_volume: DatabricksVolume, serde: Serde
) -> bytes:
    """Convert flat DatabricksVolume to nested JSON bytes."""
    return serde.encode(_databricks_volume_to_nested(databricks_volume))


def _databricks_volume_from_nested_bytes(data: bytes, serde: Serde) -> DatabricksVolume:
    """Convert nested JSON bytes to flat DatabricksVolume."""
    nested = serde.decode(data, DatabricksVolumeNested)
    return _databricks_volume_from_nested(nested)


